import React from 'react';
// import { useOrderContext } from './OrderCartContext';
import CartItemCard from './Card';
// import CartItemCard from './CartItemCard';

const CartPage = () => {
  const { order, getTotalAmount } = useOrderContext();
  const totalCartAmount = getTotalAmount();

  return (
    <div className="cart-page">
      <h2>Your Cart</h2>
      <div className="cart-items">
        {Object.keys(order).length === 0 ? (
          <p>Your cart is empty</p>
        ) : (
          Object.values(order).map(item => (
            <CartItemCard
              key={item.id}
              id={item.id}
              name={item.name}
              description={item.description}
              price={item.price}
              quantity={item.quantity}
            />
          ))
        )}
      </div>
      <div className="cart-summary">
        <p>Total Amount: ${totalCartAmount.toFixed(2)}</p>
        <button 
          onClick={() => alert("Proceeding to Payment...")} 
          className="checkout-button"
          disabled={Object.keys(order).length === 0}
        >
          Proceed to Payment
        </button>
      </div>
    </div>
  );
};

export default CartPage;
